// ─── Assemble courses ─────────────────────────────────────────────────────────

function buildById(courses) {
  return Object.fromEntries(courses.map((c) => [c.subjectId, c]))
}

function buildSeed(questionTypes) {
  // Cycle mastery patterns across learning objectives so the 3D map paints
  // a realistic mix of solid / partial / untouched disks on first visit.
  // Grouping by standardCode (LO) means a whole LO looks mastered or
  // untouched — closer to how a real student's graph reads — instead of
  // a checkerboard of single QTs.
  const PATTERNS = [
    { frac: 1.00, weakness: 0.0 },  // fully mastered
    { frac: 0.75, weakness: 0.3 },  // mostly done
    { frac: 0.50, weakness: 1.2 },  // half done
    { frac: 0.25, weakness: 2.0 },  // barely touched
    { frac: 0.00, weakness: 2.8 },  // untouched
  ]
  const byLo = {}
  questionTypes.forEach((qt) => {
    const loKey = qt.standardCode || qt.id
    ;(byLo[loKey] ||= []).push(qt)
  })
  const out = {}
  Object.keys(byLo).forEach((loKey, loIdx) => {
    const { frac, weakness } = PATTERNS[loIdx % PATTERNS.length]
    byLo[loKey].forEach((qt, qtIdxInLo) => {
      const questions = Array.isArray(qt.questions) ? qt.questions : []
      const total = questions.length
      // Nudge each QT in the same LO a little so arcs vary within a disk.
      const jitter = (qtIdxInLo % 2 === 0 ? 0 : -0.1)
      const effectiveFrac = Math.max(0, Math.min(1, frac + jitter))
      const keep = Math.round(total * effectiveFrac)
      const correctQuestionKeys = questions.slice(0, keep).map((q) => q.key).filter(Boolean)
      const weaknessScore = Math.max(0, weakness + (qtIdxInLo % 3 === 0 ? 0 : 0.2))
      out[qt.id] = { correctQuestionKeys, weaknessScore }
    })
  })
  return out
}

